import{c as e,Q as r,j as o,m as a}from"./chunks/framework.rlpw0eGz.js";const g=JSON.parse('{"title":"企业微信（WeCom / WeWork）","description":"","frontmatter":{},"headers":[],"relativePath":"zh/channels/wecom.md","filePath":"zh/channels/wecom.md","lastUpdated":1777012567000}'),l={name:"zh/channels/wecom.md"};function n(i,t,s,d,h,c){return r(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="企业微信-wecom-wework" tabindex="-1">企业微信（WeCom / WeWork） <a class="header-anchor" href="#企业微信-wecom-wework" aria-label="Permalink to &quot;企业微信（WeCom / WeWork）&quot;">​</a></h1><p>在企微工作区内收发消息，常走管理后台里自建/机器人应用。</p><h2 id="_1-建企微侧凭据" tabindex="-1">1. 建企微侧凭据 <a class="header-anchor" href="#_1-建企微侧凭据" aria-label="Permalink to &quot;1. 建企微侧凭据&quot;">​</a></h2><ol><li>登录 <a href="https://work.weixin.qq.com/" target="_blank" rel="noreferrer">企微管理后台</a> 或开发文档里指引的入口。</li><li>在 <strong>应用管理</strong> 等位置创建 <strong>自建应用</strong> 或 <strong>机器人</strong>（以你组织实际菜单为准）。</li><li>记下 <strong>AgentId / Bot ID</strong> 与 <strong>Secret</strong> 等（字段名以 Memoh 表单与企微当前文档为准）。</li></ol><h2 id="_2-在-memoh-里填" tabindex="-1">2. 在 Memoh 里填 <a class="header-anchor" href="#_2-在-memoh-里填" aria-label="Permalink to &quot;2. 在 Memoh 里填&quot;">​</a></h2><ol><li>机器人 <strong>Platforms</strong> → <strong>Add Channel</strong> → <strong>WeCom</strong>。</li><li>按表单填，常见包括：</li></ol><table tabindex="0"><thead><tr><th>字段</th><th>必填</th><th>说明</th></tr></thead><tbody><tr><td><strong>Bot ID</strong></td><td>是</td><td>企微里该机器人的标识</td></tr><tr><td><strong>Secret</strong></td><td>是</td><td>鉴权用</td></tr><tr><td><strong>WebSocket URL</strong></td><td>否</td><td>不填多用默认端点</td></tr></tbody></table><ol start="3"><li><strong>Save and Enable</strong>。</li></ol><h2 id="_3-使用" tabindex="-1">3. 使用 <a class="header-anchor" href="#_3-使用" aria-label="Permalink to &quot;3. 使用&quot;">​</a></h2><p>连上后，工作区内用户可私聊或拉群与机器人说话，行为以你企微与 Memoh 当前版本为准。</p><h2 id="支持的能力" tabindex="-1">支持的能力 <a class="header-anchor" href="#支持的能力" aria-label="Permalink to &quot;支持的能力&quot;">​</a></h2><ul><li>文本</li><li>私聊、群聊</li><li><strong>流式</strong>回复（在 Memoh 里多为实时出字，以实际为准）</li></ul><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://developer.work.weixin.qq.com/" target="_blank" rel="noreferrer">企微开放能力</a></li><li><a href="https://developer.work.weixin.qq.com/document/path/91770" target="_blank" rel="noreferrer">企微「智能机器人」等文档以官网为准</a></li></ul>',14)])])}const _=e(l,[["render",n]]);export{g as __pageData,_ as default};
